// This code assumes:
// 1. $input.item.json is the AI's updated JSON object
// 2. You have a way to reference the "original" state (e.g., from an 'Edit Fields' node)

const aiOutput = $input.first().json;
const originalState = $('Execute a SQL query').first().json.selections

/**
 * Deep merges two objects. 
 * If the source (AI) has a non-null value, it overwrites the target.
 */
function mergeSelections(target, source) {
  if (typeof source !== 'object' || source === null) {
    return target;
  }

  Object.keys(source).forEach(key => {
    const sourceValue = source[key];
    const targetValue = target[key];

    if (Array.isArray(sourceValue) && Array.isArray(targetValue)) {
      // For arrays (like layer_definitions), merge by index
      sourceValue.forEach((item, index) => {
        if (targetValue[index]) {
          targetValue[index] = mergeSelections(targetValue[index], item);
        } else {
          targetValue.push(item);
        }
      });
    } else if (typeof sourceValue === 'object' && sourceValue !== null) {
      // Recurse for nested objects
      target[key] = mergeSelections(targetValue || {}, sourceValue);
    } else {
      // Only update if the AI provided a non-null value
      if (sourceValue !== null && sourceValue !== undefined) {
        target[key] = sourceValue;
      }
    }
  });

  return target;
}

const mergedResult = mergeSelections(JSON.parse(JSON.stringify(originalState)), aiOutput);

return {
  user_selections: mergedResult
};

const order = $('save').first().json.selections;

const deliveryStatus = order.delivery === true
    ? `🚚 Delivery to: ${order.delivery_address || 'address not yet provided'}`
    : `🏠 Pickup from our bakery`;

const acStatus = order.has_ac === true ? "Yes" : "No";

const eventDate = order.event_date
    ? new Date(order.event_date).toLocaleDateString('en-US', {
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
    })
    : "Date not set";

let cakeDetails = "";
if (order.tier_definitions && Array.isArray(order.tier_definitions)) {
    const tierLabels = order.tier_definitions.length === 2 
    ? ['base', 'top'] 
    : ['base', 'middle', 'top'];
    order.tier_definitions.forEach((tier, index) => {
        const label = tierLabels[index] || `tier ${tier.tier_index}`;
        const size = tier.size ? `${tier.size}"` : 'size TBD';
        const flavor = tier.flavor || 'flavour TBD';
        const filling = tier.filling || 'filling TBD';
        const layers = tier.layers ? `${tier.layers} layers` : 'layers TBD';
        cakeDetails += `Tier ${tier.tier_index} (${label} — ${size}): ${flavor} · ${filling} · ${layers}\n`;
    });
} else {
    cakeDetails = "Cake details TBD\n";
}

// Celebrant line — only show if we have a name
const celebrantLine = order.celebrant_name && order.celebrant_name !== 'None'
    ? `🎉 For: ${order.celebrant_name}${order.celebrant_age && order.celebrant_age !== 'None' ? `, turning ${order.celebrant_age}` : ''}\n`
    : "";

// Frosting — only show if captured
const frostingLine = order.frosting_flavor && order.frosting_flavor !== 'None'
    ? `🍦 Frosting: ${order.frosting_flavor}\n`
    : "";

// Special note — guard against "None" string
const specialNote = order.special_note && order.special_note !== 'None'
    ? `💬 "${order.special_note}"\n\n`
    : "";

const tierCount = order.tiers === 1 ? '1-tier' : `${order.tiers}-tier`;
const theme = order.cake_theme && order.cake_theme !== 'None' ? ` — ${order.cake_theme}` : '';

const finalMessage =
    `Here's what I have for you, ${order.client_name || 'there'}:\n\n` +
    `🎂 ${tierCount} cake${theme}\n` +
    `📅 ${eventDate}\n` +
    `${deliveryStatus}\n` +
    `${celebrantLine}` +
    `\n${cakeDetails}\n` +
    `${frostingLine}` +
    `${specialNote}` +
    `❄️ AC venue: ${acStatus}\n\n` +
    `Does that look right, or would you like to change anything?`;

return { response_message: finalMessage };

const order = $input.first().json.selections;
const name = order?.client_name || 'there';

return {
  response_message:
    `Got it, ${name}. Your order has been sent to the team.\n\n` +
    `We'll review everything and get back to you within 24 hours with a price and next steps.`
};

const message = $input.first().json.message
const input = message.text || message.caption

// 1. BASIC SANITIZATION
// Removes HTML tags and trims whitespace to prevent basic XSS/formatting breaks
let sanitized = input.replace(/<[^>]*>?/gm, '').trim();

// 2. MALICIOUS PATTERN DETECTION
// We look for common "jailbreak" or system-level command patterns
const maliciousPatterns = [
  /system prompt/i,
  /ignore all previous instructions/i,
  /drop table/i,           // SQL Injection
  /<script/i,              // Basic Script Injection
  /bash/i, /sudo/i,        // Command Injection
  /forget your rules/i     // LLM Jailbreaking
];

let isMalicious = false;
for (const pattern of maliciousPatterns) {
  if (pattern.test(input)) {
    isMalicious = true;
    break;
  }
}

// Return the cleaned input and the flag
return {
  sanitizedInput: sanitized,
  isMalicious: isMalicious,
  originalLength: input.length
};

const authHeader = $json["headers"]["authorization"];
if (!authHeader || !authHeader.startsWith("Basic ")) {
    return [{ statusCode: 401, body: "Unauthorized" }];
}

// Decode Base64
const base64Credentials = authHeader.split(" ")[1];
const decoded = Buffer.from(base64Credentials, "base64").toString();
const [username, password] = decoded.split(":");

return [{ json: { username, password } }];

if (!$input.first().json.valid) {
    return [{ statusCode: 401, body: "Unauthorized" }];
}

return [{ statusCode: 200, body: "OK" }];

