const retrived_config = $input.first().json.order_config;
const order_config = {};

for (const key in retrived_config) {
    const current_config = retrived_config[key];
    const item_config = {};
    const option_labels = {};

    const options = current_config.options;

    // 1. Mapping the basics
    item_config['display_name'] = current_config.display_name;
    item_config['field_type'] = current_config.field_type;
    item_config['scope'] = current_config.scope; // Global vs Tier
    item_config['sort_order'] = current_config.sort_order;

    // 2. Mapping the New Intelligence
    item_config['extraction_hint'] = current_config.extraction_hint;
    item_config['rules'] = current_config.rules || []; // Integration of the field_rules table

    // 3. Handle Options
    item_config['options'] = [];
    if (options != null) {
        // Keeps the array of values for the validation 'isAllowed' check
        item_config['options'] = Object.keys(options);

        for (const opt_key in options) {
            option_labels[opt_key] = options[opt_key].label;
        }
    }

    item_config['option_labels'] = option_labels;

    // 4. Placeholder for future price logic if added to field_rules/options
    item_config['option_prices'] = {}; 

    order_config[key] = item_config;
}

return { order_config: order_config };
